// Validate the shared-secret header. Postmark webhooks are unauthenticated
// by default; we require a custom header that Mary configures in the
// Postmark UI under Webhooks > Custom HTTP headers. The expected value
// lives in $env.POSTMARK_WEBHOOK_TOKEN on the n8n host.
const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const expected = ($env && $env.POSTMARK_WEBHOOK_TOKEN) || '';
const supplied = headers['x-postmark-webhook-token'] || headers['X-Postmark-Webhook-Token'] || '';

if (!expected) {
  return { json: { ok: false, status: 500, error: 'POSTMARK_WEBHOOK_TOKEN env var not set on n8n host' } };
}
if (supplied !== expected) {
  return { json: { ok: false, status: 401, error: 'Invalid or missing webhook token' } };
}

// Normalize Postmark RecordType -> our event_type enum.
const RECORD_TO_TYPE = {
  Delivery:           'delivery',
  Bounce:             'bounce',
  SpamComplaint:      'spam_complaint',
  Open:               'open',
  Click:              'click',
  SubscriptionChange: 'subscription_change'
};
const recordType = body.RecordType || '';
const eventType = RECORD_TO_TYPE[recordType] || 'other';

// Postmark ships ReceivedAt for most types, BouncedAt for Bounce,
// ChangedAt for SubscriptionChange. Pick the most specific timestamp
// the event provides.
const receivedAt = body.ReceivedAt || body.BouncedAt || body.DeliveredAt
  || body.ChangedAt || body.ReceivedAtUtc || new Date().toISOString();

// Bounce has a Type (HardBounce, SoftBounce, Transient, DnsError, etc.)
// and a TypeCode. Keep the human-readable Type as our subtype.
const bounceSubtype = (recordType === 'Bounce') ? (body.Type || null) : null;

const row = {
  event_type:          eventType,
  bounce_subtype:      bounceSubtype,
  postmark_message_id: body.MessageID || body.MessageId || null,
  recipient:           body.Recipient || body.Email || (body.To && Array.isArray(body.To) ? (body.To[0] && body.To[0].Email) : (body.To || null)),
  from_email:          body.From || null,
  subject:             body.Subject || null,
  tag:                 body.Tag || null,
  message_stream:      body.MessageStream || null,
  description:         body.Description || null,
  details:             body.Details || null,
  server_id:           body.ServerID != null ? String(body.ServerID) : null,
  received_at:         receivedAt,
  raw_payload:         body,
  metadata:            body.Metadata || {}
};

return { json: { ok: true, status: 200, row: row, record_type: recordType, event_type: eventType } };

// Always ack 200 to Postmark even if the insert errored — Postmark
// retries with backoff if we 5xx, but we'd rather lose one event than
// hammer a Supabase outage. The insert node is continueOnFail; pull its
// status here for the response body.
const v = $('Validate + Normalize').item.json;
const insert = $input.item ? $input.item.json : {};
const insertedOk = !(insert && (insert.error || insert.message === 'error' || insert.code));
return { json: {
  ok: insertedOk,
  event_type: v.event_type,
  record_type: v.record_type,
  inserted: insertedOk,
  insert_error: insertedOk ? null : (insert.error || insert.message || JSON.stringify(insert).slice(0, 300))
} };
